import { NavLink } from "react-router-dom";
import './Navbar.css'
function Navbar (){
    return(
        <div id="Navbar">
            <NavLink className='nav-items'to="/">Home</NavLink>
            <NavLink to="/pastes">All Pastes</NavLink>
        </div>
    )
}
export default Navbar;
